#include <stdio.h>
#include <stdlib.h>

int canMake(int *a, int n, int m, int k, int day) {
    int bouquets = 0, cnt = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] <= day) {
            ++cnt;
            if (cnt == k) {
                ++bouquets;
                cnt = 0;
                if (bouquets >= m) return 1;
            }
        } else {
            cnt = 0;
        }
    }
    return bouquets >= m;
}

int minDays(int *a, int n, int m, int k) {
    if ((long long)m * k > n) return -1;
    int low = 1, high = a[0];
    for (int i = 1; i < n; ++i) if (a[i] > high) high = a[i];
    int ans = -1;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if (canMake(a, n, m, k, mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return ans;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, m, k; scanf("%d %d %d", &N, &m, &k);
        int *bloom = (int*)malloc(sizeof(int) * N);
        for (int i = 0; i < N; ++i) scanf("%d", &bloom[i]);
        int res = minDays(bloom, N, m, k);
        printf("%d\n", res);
        free(bloom);
    }
    return 0;
}

