import sys

def can_make(arr, m, k, day):
    bouquets = cnt = 0
    for v in arr:
        if v <= day:
            cnt += 1
            if cnt == k:
                bouquets += 1
                cnt = 0
                if bouquets >= m:
                    return True
        else:
            cnt = 0
    return bouquets >= m

def min_days(arr, m, k):
    if m * k > len(arr):
        return -1
    low, high = 1, max(arr)
    ans = -1
    while low <= high:
        mid = (low + high) // 2
        if can_make(arr, m, k, mid):
            ans = mid
            high = mid - 1
        else:
            low = mid + 1
    return ans

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); m = int(next(it)); k = int(next(it))
        bloom = [int(next(it)) for _ in range(N)]
        out.append(str(min_days(bloom, m, k)))
    sys.stdout.write('\n'.join(out))

